        config.timeoutIntervalForRequest = 30
        config.timeoutIntervalForResource = 300
        session = URLSession(configuration: config)
    }
    
    func setAuthToken(_ token: String) {
        self.authToken = token
    }
    
    private func createRequest(endpoint: String, method: String, body: [String: Any]? = nil) throws -> URLRequest {
        guard let url = URL(string: baseURL + endpoint) else {
            throw NetworkError.invalidURL
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = method
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        if let token = authToken {
            request.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        }
        
        if let body = body {
            request.httpBody = try JSONSerialization.data(withJSONObject: body)
        }
        
        return request
    }
    
    func executeTrade(order: TradeOrder, completion: @escaping (Result<TradeConfirmation, Error>) -> Void) {
        let body: [String: Any] = [
            "symbol": order.symbol,
            "quantity": order.quantity,
            "orderType": order.orderType.rawValue,
            "side": order.side.rawValue,
            "price": order.price ?? 0,
            "timeInForce": order.timeInForce.rawValue
        ]
        
        do {
            let request = try createRequest(endpoint: "/orders", method: "POST", body: body)
            
            session.dataTask(with: request) { data, response, error in
                if let error = error {
                    completion(.failure(error))
                    return
                }
                
                guard let data = data else {
                    completion(.failure(NetworkError.noData))
