                }
                
                do {
                    let confirmation = try JSONDecoder().decode(TradeConfirmation.self, from: data)
                    completion(.success(confirmation))
                } catch {
                    completion(.failure(error))
                }
            }.resume()
        } catch {
            completion(.failure(error))
        }
    }
    
    func cancelOrder(orderId: String, completion: @escaping (Result<Bool, Error>) -> Void) {
