enum NetworkError: Error {
    case invalidURL
    case noData
    case invalidResponse
}

enum OrderType: String, Codable {
    case market = "MARKET"
    case limit = "LIMIT"
    case stop = "STOP"
    case stopLimit = "STOP_LIMIT"
}

enum OrderSide: String, Codable {
    case buy = "BUY"
    case sell = "SELL"
}

enum TimeInForce: String, Codable {
    case day = "DAY"
    case gtc = "GTC"
    case ioc = "IOC"
    case fok = "FOK"
}

enum OrderStatus: String, Codable {
    case pending = "PENDING"
    case filled = "FILLED"
    case partiallyFilled = "PARTIALLY_FILLED"
    case cancelled = "CANCELLED"
    case rejected = "REJECTED"
}

struct TradeOrder {
    let symbol: String
    let quantity: Double
    let orderType: OrderType
    let side: OrderSide
    let price: Double?
    let timeInForce: TimeInForce
}

struct TradeConfirmation: Codable {
    let orderId: String
    let symbol: String
    let quantity: Double
    let price: Double
    let side: OrderSide
    let orderType: OrderType
    let status: OrderStatus
    let filledQuantity: Double
    let averagePrice: Double
    let timestamp: Date
}

struct Portfolio: Codable {
    let positions: [Position]
    let totalValue: Double
    let cashBalance: Double
    let todayProfitLoss: Double
    let totalProfitLoss: Double
}

struct Position: Codable {
    let symbol: String
    let quantity: Double
    let averageCost: Double
    let currentPrice: Double
    let marketValue: Double
    let profitLoss: Double
    let profitLossPercent: Double
}

struct StockQuote: Codable {
    let symbol: String
    let price: Double
    let bid: Double
    let ask: Double
    let volume: Int64
    let previousClose: Double
    let change: Double
    let changePercent: Double
    let timestamp: Date
}

struct AccountBalance: Codable {
    let cashAvailable: Double
    let buyingPower: Double
    let portfolioValue: Double
    let totalEquity: Double
}

class PortfolioManager {
    static let shared = PortfolioManager()
    private var portfolio: Portfolio?
    private var positions: [String: Position] = [:]
    @Published var portfolioUpdated = false
    
    private init() {}
    
    func loadPortfolio(completion: @escaping (Bool) -> Void) {
        TradingAPI.shared.getPortfolio { [weak self] result in
            switch result {
            case .success(let portfolio):
                self?.portfolio = portfolio
                self?.positions = Dictionary(uniqueKeysWithValues: portfolio.positions.map { ($0.symbol, $0) })
                self?.portfolioUpdated.toggle()
                completion(true)
            case .failure:
                completion(false)
            }
        }
    }
    
    func getPosition(for symbol: String) -> Position? {
        return positions[symbol]
    }
    
    func getTotalValue() -> Double {
        return portfolio?.totalValue ?? 0
    }
    
    func getCashBalance() -> Double {
        return portfolio?.cashBalance ?? 0
    }
    
    func getTodayProfitLoss() -> Double {
        return portfolio?.todayProfitLoss ?? 0
    }
    
    func getTotalProfitLoss() -> Double {
        return portfolio?.totalProfitLoss ?? 0
    }
    
    func getAllPositions() -> [Position] {
        return portfolio?.positions ?? []
    }
}

class TradeExecutor {
    static let shared = TradeExecutor()
    private var pendingOrders: [String: TradeConfirmation] = [:]
    
    private init() {}
    
    func executeTrade(order: TradeOrder, completion: @escaping (Result<TradeConfirmation, Error>) -> Void) {
        TradingAPI.shared.executeTrade(order: order) { [weak self] result in
            switch result {
            case .success(let confirmation):
                self?.pendingOrders[confirmation.orderId] = confirmation
                completion(.success(confirmation))
            case .failure(let error):
                completion(.failure(error))
            }
        }
    }
    
    func cancelOrder(orderId: String, completion: @escaping (Bool) -> Void) {
        TradingAPI.shared.cancelOrder(orderId: orderId) { [weak self] result in
            switch result {
            case .success(let cancelled):
                if cancelled {
                    self?.pendingOrders.removeValue(forKey: orderId)
                }
                completion(cancelled)
            case .failure:
                completion(false)
            }
        }
    }
    
    func getPendingOrders() -> [TradeConfirmation] {
        return Array(pendingOrders.values)
    }
}

