        symbolTextField.borderStyle = .roundedRect
        symbolTextField.autocapitalizationType = .allCharacters
        symbolTextField.translatesAutoresizingMaskIntoConstraints = false
        view.addSubview(symbolTextField)
        
        quantityTextField.placeholder = "Quantity"
        quantityTextField.borderStyle = .roundedRect
        quantityTextField.keyboardType = .decimalPad
        quantityTextField.translatesAutoresizingMaskIntoConstraints = false
        view.addSubview(quantityTextField)
        
        priceTextField.placeholder = "Price (for limit orders)"
        priceTextField.borderStyle = .roundedRect
        priceTextField.keyboardType = .decimalPad
        priceTextField.translatesAutoresizingMaskIntoConstraints = false
        view.addSubview(priceTextField)
        
        orderTypeSegment.selectedSegmentIndex = 0
        orderTypeSegment.translatesAutoresizingMaskIntoConstraints = false
        orderTypeSegment.addTarget(self, action: #selector(orderTypeChanged), for: .valueChanged)
        view.addSubview(orderTypeSegment)
        
        sideSegment.selectedSegmentIndex = 0
        sideSegment.translatesAutoresizingMaskIntoConstraints = false
        view.addSubview(sideSegment)
        
        quoteLabel.numberOfLines = 0
        quoteLabel.textAlignment = .center
        quoteLabel.translatesAutoresizingMaskIntoConstraints = false
        view.addSubview(quoteLabel)
        
        executeButton.setTitle("Execute Trade", for: .normal)
        executeButton.backgroundColor = .systemBlue
        executeButton.setTitleColor(.white, for: .normal)
        executeButton.layer.cornerRadius = 8
        executeButton.translatesAutoresizingMaskIntoConstraints = false
        executeButton.addTarget(self, action: #selector(executeTrade), for: .touchUpInside)
        view.addSubview(executeButton)
        
        NSLayoutConstraint.activate([
            symbolTextField.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor, constant: 20),
            symbolTextField.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 20),
            symbolTextField.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -20),
            symbolTextField.heightAnchor.constraint(equalToConstant: 44),
            
            quoteLabel.topAnchor.constraint(equalTo: symbolTextField.bottomAnchor, constant: 10),
            quoteLabel.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 20),
            quoteLabel.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -20),
            
            quantityTextField.topAnchor.constraint(equalTo: quoteLabel.bottomAnchor, constant: 20),
            quantityTextField.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 20),
            quantityTextField.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -20),
            quantityTextField.heightAnchor.constraint(equalToConstant: 44),
            
            orderTypeSegment.topAnchor.constraint(equalTo: quantityTextField.bottomAnchor, constant: 20),
            orderTypeSegment.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 20),
            orderTypeSegment.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -20),
            
            priceTextField.topAnchor.constraint(equalTo: orderTypeSegment.bottomAnchor, constant: 20),
            priceTextField.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 20),
            priceTextField.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -20),
            priceTextField.heightAnchor.constraint(equalToConstant: 44),
            
            sideSegment.topAnchor.constraint(equalTo: priceTextField.bottomAnchor, constant: 20),
            sideSegment.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 20),
            sideSegment.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -20),
            
            executeButton.topAnchor.constraint(equalTo: sideSegment.bottomAnchor, constant: 30),
            executeButton.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 20),
            executeButton.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -20),
            executeButton.heightAnchor.constraint(equalToConstant: 50)
        ])
        
        orderTypeChanged()
    }
    
    @objc private func orderTypeChanged() {
        priceTextField.isEnabled = orderTypeSegment.selectedSegmentIndex == 1
        priceTextField.alpha = orderTypeSegment.selectedSegmentIndex == 1 ? 1.0 : 0.5
    }
    
    private func startQuoteUpdates() {
        timer = Timer.scheduledTimer(withTimeInterval: 5.0, repeats: true) { [weak self] _ in
            self?.updateQuote()
        }
    }
    
    private func updateQuote() {
        guard let symbol = symbolTextField.text, !symbol.isEmpty else { return }
        
        TradingAPI.shared.getStockQuote(symbol: symbol) { [weak self] result in
            DispatchQueue.main.async {
                switch result {
                case .success(let quote):
                    self?.currentQuote = quote
                    self?.displayQuote(quote)
                case .failure:
                    self?.quoteLabel.text = "Unable to fetch quote"
                }
            }
        }
    }
    
    private func displayQuote(_ quote: StockQuote) {
        let changeColor = quote.change >= 0 ? UIColor.systemGreen : UIColor.systemRed
        let changeText = String(format: "%.2f (%.2f%%)", quote.change, quote.changePercent)
        
        let text = NSMutableAttributedString()
        text.append(NSAttributedString(string: "\(quote.symbol)\n", attributes: [.font: UIFont.boldSystemFont(ofSize: 20)]))
        text.append(NSAttributedString(string: String(format: "$%.2f\n", quote.price), attributes: [.font: UIFont.systemFont(ofSize: 24)]))
        text.append(NSAttributedString(string: changeText, attributes: [.foregroundColor: changeColor, .font: UIFont.systemFont(ofSize: 16)]))
        
        quoteLabel.attributedText = text
    }
    
    @objc private func executeTrade() {
        guard let symbol = symbolTextField.text, !symbol.isEmpty,
              let quantityText = quantityTextField.text, let quantity = Double(quantityText) else {
            showAlert(message: "Please enter symbol and quantity")
            return
        }
        
        let orderType: OrderType = orderTypeSegment.selectedSegmentIndex == 0 ? .market : .limit
        let side: OrderSide = sideSegment.selectedSegmentIndex == 0 ? .buy : .sell
        
        var price: Double? = nil
        if orderType == .limit {
            guard let priceText = priceTextField.text, let limitPrice = Double(priceText) else {
                showAlert(message: "Please enter a limit price")
                return
            }
            price = limitPrice
        }
        
        let order = TradeOrder(symbol: symbol, quantity: quantity, orderType: orderType, side: side, price: price, timeInForce: .day)
        
        executeButton.isEnabled = false
        executeButton.setTitle("Executing...", for: .normal)
        
        TradeExecutor.shared.executeTrade(order: order) { [weak self] result in
            DispatchQueue.main.async {
                self?.executeButton.isEnabled = true
                self?.executeButton.setTitle("Execute Trade", for: .normal)
                
                switch result {
                case .success(let confirmation):
                    self?.showAlert(message: "Order executed successfully!\nOrder ID: \(confirmation.orderId)\nStatus: \(confirmation.status.rawValue)")
                case .failure(let error):
                    self?.showAlert(message: "Error executing trade: \(error.localizedDescription)")
                }
            }
        }
    }
    
    private func showAlert(message: String) {
        let alert = UIAlertController(title: "Trade", message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
    
    deinit {
        timer?.invalidate()
    }
}

class PortfolioViewController: UIViewController, UITableViewDelegate, UITableViewDataSource {
    private let tableView = UITableView()
    private let headerView = UIView()
    private let totalValueLabel = UILabel()
    private let profitLossLabel = UILabel()
    private let cashLabel = UILabel()
    private var positions: [Position] = []
    private let refreshControl = UIRefreshControl()
    
    override func viewDidLoad() {
        super.viewDidLoad()
        setupUI()
        loadPortfolio()
    }
    
    override func viewWillAppear(_ animated: Bool) {
        super.viewWillAppear(animated)
        loadPortfolio()
    }
    
    private func setupUI() {
        view.backgroundColor = .systemBackground
        title = "Portfolio"
        
        headerView.backgroundColor = .systemGray6
        headerView.translatesAutoresizingMaskIntoConstraints = false
        view.addSubview(headerView)
        
        totalValueLabel.font = .boldSystemFont(ofSize: 24)
        totalValueLabel.translatesAutoresizingMaskIntoConstraints = false
        headerView.addSubview(totalValueLabel)
        
        profitLossLabel.font = .systemFont(ofSize: 16)
        profitLossLabel.translatesAutoresizingMaskIntoConstraints = false
        headerView.addSubview(profitLossLabel)
        
        cashLabel.font = .systemFont(ofSize: 14)
        cashLabel.textColor = .secondaryLabel
        cashLabel.translatesAutoresizingMaskIntoConstraints = false
        headerView.addSubview(cashLabel)
        
        tableView.delegate = self
        tableView.dataSource = self
        tableView.register(PositionCell.self, forCellReuseIdentifier: "PositionCell")
        tableView.translatesAutoresizingMaskIntoConstraints = false
        tableView.refreshControl = refreshControl
        refreshControl.addTarget(self, action: #selector(refreshPortfolio), for: .valueChanged)
        view.addSubview(tableView)
        
        NSLayoutConstraint.activate([
            headerView.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor),
            headerView.leadingAnchor.constraint(equalTo: view.leadingAnchor),
            headerView.trailingAnchor.constraint(equalTo: view.trailingAnchor),
            headerView.heightAnchor.constraint(equalToConstant: 120),
            
            totalValueLabel.topAnchor.constraint(equalTo: headerView.topAnchor, constant: 15),
            totalValueLabel.centerXAnchor.constraint(equalTo: headerView.centerXAnchor),
            
            profitLossLabel.topAnchor.constraint(equalTo: totalValueLabel.bottomAnchor, constant: 10),
            profitLossLabel.centerXAnchor.constraint(equalTo: headerView.centerXAnchor),
            
            cashLabel.topAnchor.constraint(equalTo: profitLossLabel.bottomAnchor, constant: 10),
            cashLabel.centerXAnchor.constraint(equalTo: headerView.centerXAnchor),
            
            tableView.topAnchor.constraint(equalTo: headerView.bottomAnchor),
            tableView.leadingAnchor.constraint(equalTo: view.leadingAnchor),
            tableView.trailingAnchor.constraint(equalTo: view.trailingAnchor),
            tableView.bottomAnchor.constraint(equalTo: view.bottomAnchor)
        ])
    }
    
    @objc private func refreshPortfolio() {
        loadPortfolio()
    }
    
    private func loadPortfolio() {
        PortfolioManager.shared.loadPortfolio { [weak self] success in
            DispatchQueue.main.async {
                self?.refreshControl.endRefreshing()
                if success {
                    self?.updateUI()
                }
            }
        }
    }
    
    private func updateUI() {
        let totalValue = PortfolioManager.shared.getTotalValue()
        let profitLoss = PortfolioManager.shared.getTotalProfitLoss()
        let cash = PortfolioManager.shared.getCashBalance()
        
        totalValueLabel.text = String(format: "$%.2f", totalValue)
        
        let profitLossColor = profitLoss >= 0 ? UIColor.systemGreen : UIColor.systemRed
        let profitLossSign = profitLoss >= 0 ? "+" : ""
        profitLossLabel.text = String(format: "%@$%.2f", profitLossSign, profitLoss)
        profitLossLabel.textColor = profitLossColor
        
        cashLabel.text = String(format: "Cash: $%.2f", cash)
        
        positions = PortfolioManager.shared.getAllPositions()
        tableView.reloadData()
    }
    
    func tableView(_ tableView: UITableView, numberOfRowsInSection section: Int) -> Int {
        return positions.count
    }
    
    func tableView(_ tableView: UITableView, cellForRowAt indexPath: IndexPath) -> UITableViewCell {
        let cell = tableView.dequeueReusableCell(withIdentifier: "PositionCell", for: indexPath) as! PositionCell
        cell.configure(with: positions[indexPath.row])
        return cell
    }
    
    func tableView(_ tableView: UITableView, heightForRowAt indexPath: IndexPath) -> CGFloat {
        return 80
    }
    
    func tableView(_ tableView: UITableView, didSelectRowAt indexPath: IndexPath) {
        tableView.deselectRow(at: indexPath, animated: true)
    }
}

