        tableView.dataSource = self
        tableView.register(OrderCell.self, forCellReuseIdentifier: "OrderCell")
        tableView.translatesAutoresizingMaskIntoConstraints = false
        tableView.refreshControl = refreshControl
        refreshControl.addTarget(self, action: #selector(refreshOrders), for: .valueChanged)
        view.addSubview(tableView)
        
        NSLayoutConstraint.activate([
            tableView.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor),
            tableView.leadingAnchor.constraint(equalTo: view.leadingAnchor),
            tableView.trailingAnchor.constraint(equalTo: view.trailingAnchor),
            tableView.bottomAnchor.constraint(equalTo: view.bottomAnchor)
        ])
    }
    
    @objc private func refreshOrders() {
        loadOrderHistory()
    }
    
    private func loadOrderHistory() {
        TradingAPI.shared.getOrderHistory { [weak self] result in
            DispatchQueue.main.async {
                self?.refreshControl.endRefreshing()
                switch result {
                case .success(let orders):
                    self?.orders = orders.sorted { $0.timestamp > $1.timestamp }
                    self?.tableView.reloadData()
                case .failure:
                    break
                }
            }
        }
    }
    
    func tableView(_ tableView: UITableView, numberOfRowsInSection section: Int) -> Int {
        return orders.count
    }
    
    func tableView(_ tableView: UITableView, cellForRowAt indexPath: IndexPath) -> UITableViewCell {
        let cell = tableView.dequeueReusableCell(withIdentifier: "OrderCell", for: indexPath) as! OrderCell
        cell.configure(with: orders[indexPath.row])
        return cell
    }
    
    func tableView(_ tableView: UITableView, heightForRowAt indexPath: IndexPath) -> CGFloat {
        return 100
    }
}

class OrderCell: UITableViewCell {
    private let symbolLabel = UILabel()
    private let detailsLabel = UILabel()
    private let statusLabel = UILabel()
    private let timestampLabel = UILabel()
    
    override init(style: UITableViewCell.CellStyle, reuseIdentifier: String?) {
        super.init(style: style, reuseIdentifier: reuseIdentifier)
        setupUI()
    }
    
    required init?(coder: NSCoder) {
        fatalError("init(coder:) has not been implemented")
    }
    
    private func setupUI() {
        symbolLabel.font = .boldSystemFont(ofSize: 18)
        symbolLabel.translatesAutoresizingMaskIntoConstraints = false
        contentView.addSubview(symbolLabel)
        
        detailsLabel.font = .systemFont(ofSize: 14)
        detailsLabel.textColor = .secondaryLabel
        detailsLabel.numberOfLines = 2
        detailsLabel.translatesAutoresizingMaskIntoConstraints = false
        contentView.addSubview(detailsLabel)
        
        statusLabel.font = .systemFont(ofSize: 14)
        statusLabel.textAlignment = .right
        statusLabel.translatesAutoresizingMaskIntoConstraints = false
        contentView.addSubview(statusLabel)
        
        timestampLabel.font = .systemFont(ofSize: 12)
        timestampLabel.textColor = .tertiaryLabel
        timestampLabel.textAlignment = .right
        timestampLabel.translatesAutoresizingMaskIntoConstraints = false
        contentView.addSubview(timestampLabel)
        
        NSLayoutConstraint.activate([
            symbolLabel.topAnchor.constraint(equalTo: contentView.topAnchor, constant: 10),
            symbolLabel.leadingAnchor.constraint(equalTo: contentView.leadingAnchor, constant: 15),
            
            detailsLabel.topAnchor.constraint(equalTo: symbolLabel.bottomAnchor, constant: 5),
            detailsLabel.leadingAnchor.constraint(equalTo: contentView.leadingAnchor, constant: 15),
            detailsLabel.trailingAnchor.constraint(equalTo: statusLabel.leadingAnchor, constant: -10),
            
            statusLabel.topAnchor.constraint(equalTo: contentView.topAnchor, constant: 10),
            statusLabel.trailingAnchor.constraint(equalTo: contentView.trailingAnchor, constant: -15),
            statusLabel.widthAnchor.constraint(equalToConstant: 100),
            
            timestampLabel.topAnchor.constraint(equalTo: statusLabel.bottomAnchor, constant: 5),
            timestampLabel.trailingAnchor.constraint(equalTo: contentView.trailingAnchor, constant: -15)
        ])
    }
    
    func configure(with order: TradeConfirmation) {
        symbolLabel.text = order.symbol
        
        let sideText = order.side == .buy ? "BUY" : "SELL"
        let sideColor = order.side == .buy ? UIColor.systemGreen : UIColor.systemRed
        
        let detailText = String(format: "%@ %.2f shares @ $%.2f\n%@", sideText, order.quantity, order.price, order.orderType.rawValue)
        detailsLabel.text = detailText
        
        statusLabel.text = order.status.rawValue
        
        switch order.status {
        case .filled:
            statusLabel.textColor = .systemGreen
        case .cancelled, .rejected:
            statusLabel.textColor = .systemRed
        default:
            statusLabel.textColor = .systemOrange
        }
        
        let formatter = DateFormatter()
        formatter.dateFormat = "MM/dd HH:mm"
        timestampLabel.text = formatter.string(from: order.timestamp)
    }
}

